const cookieStr = $('🍪 Cookies holen').first().json.cookieString || '';
const eventsResp = $('📋 Aktive Events holen').first().json;
const events = (eventsResp.list || []).filter(e => e.EventLink && e.Status !== 'inaktiv');

if (!events.length) return [{ json: { error: 'Keine aktiven Events in DB' } }];
if (!cookieStr) return [{ json: { error: 'Keine Cookies verfügbar' } }];

const knowledge = [];

for (const event of events) {
  const { Id, EventName, EventLink, EventDatum } = event;
  let html = '';
  try {
    html = await this.helpers.httpRequest({
      method: 'GET',
      url: EventLink,
      headers: {
        Cookie: cookieStr,
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/122.0.0.0 Safari/537.36',
        Accept: 'text/html,application/xhtml+xml',
        'Accept-Language': 'de-DE,de;q=0.9'
      },
      timeout: 25000,
      followRedirects: true
    });
    if (typeof html !== 'string') html = JSON.stringify(html);
  } catch(e) {
    console.log('Fetch error ' + EventName + ':', e.message);
    continue;
  }

  if (html.length < 500) continue;

  // Preise: z.B. "Frauen: 35 Euro" oder "Damen: ab 25 €"
  const preisBlock = html.match(/(?:Eintritt|Preise?|Ticketpreise?)([\s\S]{0,1200})(?=<\/(?:div|section|p)|(?:Dresscode|Ablauf|Anmeldung|<h[23]))/i);
  let preise = '';
  if (preisBlock) {
    preise = preisBlock[0].replace(/<[^>]+>/g, ' ').replace(/&[^;]+;/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 600);
  } else {
    // Fallback: alle Preis-Patterns im gesamten HTML
    const allPreis = [...html.matchAll(/(\d+)\s*(?:Euro|€)[^<]{0,80}/g)];
    if (allPreis.length) preise = allPreis.slice(0,8).map(m => m[0].replace(/<[^>]+>/g,'').trim()).join(' | ').substring(0,400);
  }

  // Dresscode
  const dressM = html.match(/(?:Dresscode|Dress[- ]?Code)[^<]{0,400}(?=<\/(?:div|p|li)|Eintritt|Preise)/i)
               || html.match(/(?:Dresscode|Dress[- ]?Code)([\s\S]{0,400}?)(?=<(?:div|p|ul|br))/i);
  const dresscode = dressM ? dressM[0].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 300) : '';

  // Event-Beschreibung (Haupt-Content)
  const descM = html.match(/class="event_description[^"]*"[^>]*>([\s\S]*?)(?=<div[^>]*(?:event_detail_tab|clearfix)|<div id="guest_list)/i)
              || html.match(/<article[^>]*>([\s\S]{100,3000}?)<\/article>/i);
  let beschreibung = '';
  if (descM) {
    beschreibung = descM[1]
      .replace(/<script[\s\S]*?<\/script>/gi, '')
      .replace(/<style[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&[^;]+;/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .substring(0, 1500);
  }

  // Kapazität
  const kapM = html.match(/(\d+)\s*(?:Gäste|Personen|Plätze|Tickets)\s*(?:gesamt|max|insgesamt|verfügbar)/i)
             || html.match(/(?:maximal|max\.)\s*(\d+)\s*(?:Gäste|Personen)/i);
  const kapazitaet = kapM ? kapM[1] : '';

  // Datum/Uhrzeit
  const zeitM = html.match(/(\d{1,2}:\d{2})\s*(?:Uhr)?\s*(?:Einlass|Beginn|Start|ab)/i)
              || html.match(/(?:Einlass|Beginn|Start|ab)\s*(\d{1,2}:\d{2})/i);
  const uhrzeit = zeitM ? zeitM[1] : '';

  // Anmeldungs-URL (Anmeldeseite)
  const regM = html.match(/href="([^"]*(?:anmeldung|registration|guest_list|anmelden)[^"]*)"/i);
  const anmeldungUrl = regM ? regM[1] : EventLink + '#guest_list';

  const entry = {
    id: Id,
    name: EventName,
    datum: EventDatum,
    link: EventLink,
    preise: preise || '(nicht gefunden)',
    dresscode: dresscode || '(nicht angegeben)',
    beschreibung: beschreibung || '(keine Beschreibung)',
    kapazitaet: kapazitaet || '',
    uhrzeit: uhrzeit || '',
    anmeldungUrl,
    scrapedAt: new Date().toISOString()
  };

  knowledge.push(entry);
  console.log('✓ ' + EventName + ' – Preis gefunden: ' + !!preise + ', Dresscode: ' + !!dresscode);
}

return [{ json: { knowledge, count: knowledge.length, updatedAt: new Date().toISOString() } }];
